# -*- coding: utf-8 -*-
import base64, os

static = os.path.join(os.path.expanduser("~"), "Desktop", "Python", "scanner", "static")
os.makedirs(static, exist_ok=True)

html_b64 = ""

with open(os.path.join(static, "index.html"), "wb") as f:
    f.write(base64.b64decode(html_b64))
print("index.html instalado com sucesso!")
